external_knowledge:
'popular surveys' refers to surveys with more than 100 responses;
'a lot of responses' indicates the number of responses exceeds 100;
'accessed multiple times' means the survey has been accessed more than 5 times.

sql:
SELECT COUNT(DISTINCT user_id)
FROM viz_access
WHERE access_type = 'view';

SELECT survey_id 
FROM survey_responses 
WHERE response_date BETWEEN date('now', '-30 days') AND date('now');

SELECT d.age, d.gender
FROM demographics AS d
INNER JOIN survey_responses AS sr ON d.demog_id = sr.demog_id;

SELECT marital_status, COUNT(*) AS count
FROM demographics
GROUP BY marital_status;

SELECT d.voter_registration_status
FROM survey_responses sr
INNER JOIN demographics d ON d.demog_id = sr.demog_id;

SELECT COUNT(DISTINCT user_id) AS user_view_count
FROM viz_access
WHERE access_type = 'view';
